import{_ as e,o as l,c as r,ai as i}from"./chunks/framework.BIXs0jTs.js";const o="/assets/preface-cover.Balx8Fq4.png",g=JSON.parse('{"title":"在团队中落地 Claude Code、Skill 与 MCP","description":"","frontmatter":{"title":"在团队中落地 Claude Code、Skill 与 MCP"},"headers":[],"relativePath":"40-practices/team-adoption.md","filePath":"40-practices/team-adoption.md","lastUpdated":null}'),t={name:"40-practices/team-adoption.md"};function n(d,a,s,h,c,u){return l(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="第-15-章-在团队中落地-claude-code、skill-与-mcp" tabindex="-1">第 15 章　在团队中落地 Claude Code、Skill 与 MCP <a class="header-anchor" href="#第-15-章-在团队中落地-claude-code、skill-与-mcp" aria-label="Permalink to &quot;第 15 章　在团队中落地 Claude Code、Skill 与 MCP&quot;">​</a></h1><p><img src="'+o+'" alt="团队落地：文化建设与流程规范"></p><p>当你读到这里，相信你已经是一个 Claude Code 的超级用户了。但软件开发从来不是一个人的战斗。</p><p>如何让你的团队、你的部门甚至整个公司都从这套工具链中受益？这不仅是一个技术问题，更是一个<strong>文化</strong>和<strong>管理</strong>问题。</p><h2 id="_15-1-团队认知与共识建设" tabindex="-1">15.1 团队认知与共识建设 <a class="header-anchor" href="#_15-1-团队认知与共识建设" aria-label="Permalink to &quot;15.1 团队认知与共识建设&quot;">​</a></h2><p>在推广任何新工具之前，首先要解决“人”的问题。</p><h3 id="_15-1-1-消除恐惧-ai-是副驾驶-不是替代者" tabindex="-1">15.1.1 消除恐惧：AI 是副驾驶，不是替代者 <a class="header-anchor" href="#_15-1-1-消除恐惧-ai-是副驾驶-不是替代者" aria-label="Permalink to &quot;15.1.1 消除恐惧：AI 是副驾驶，不是替代者&quot;">​</a></h3><p>很多工程师担心：“用了 AI，我会不会失业？”</p><p>你需要明确传达一个观念：<strong>Claude Code 是为了让你从重复劳动中解脱出来，去做更有创造性的工作。</strong></p><ul><li>它帮你写样板代码，你负责架构设计。</li><li>它帮你查日志，你负责根因分析。</li></ul><h3 id="_15-1-2-设定合理的预期" tabindex="-1">15.1.2 设定合理的预期 <a class="header-anchor" href="#_15-1-2-设定合理的预期" aria-label="Permalink to &quot;15.1.2 设定合理的预期&quot;">​</a></h3><p>不要把 Claude 吹成神。</p><ul><li><strong>Yes</strong>: 它能加速编码，提高测试覆盖率，辅助排查问题。</li><li><strong>No</strong>: 它不能完全独立工作，它的代码必须经过人工审查。</li></ul><h2 id="_15-2-制定团队-ai-使用规范" tabindex="-1">15.2 制定团队 AI 使用规范 <a class="header-anchor" href="#_15-2-制定团队-ai-使用规范" aria-label="Permalink to &quot;15.2 制定团队 AI 使用规范&quot;">​</a></h2><p>没有规矩，不成方圆。为了防止乱象，你需要制定一份《团队 AI 协作指南》。</p><h3 id="_15-2-1-安全红线-security-first" tabindex="-1">15.2.1 安全红线 (Security First) <a class="header-anchor" href="#_15-2-1-安全红线-security-first" aria-label="Permalink to &quot;15.2.1 安全红线 (Security First)&quot;">​</a></h3><ul><li><strong>绝不上传机密数据</strong>：严禁将客户 PII（个人隐私信息）、生产环境密钥直接发送给 LLM。</li><li><strong>使用 MCP 时的权限控制</strong>：生产环境的 MCP Server 必须配置为 Read-Only，或者需要人工审批（Human-in-the-loop）。</li></ul><h3 id="_15-2-2-代码审查-code-review" tabindex="-1">15.2.2 代码审查 (Code Review) <a class="header-anchor" href="#_15-2-2-代码审查-code-review" aria-label="Permalink to &quot;15.2.2 代码审查 (Code Review)&quot;">​</a></h3><p>AI 写的代码<strong>必须</strong>像实习生写的代码一样对待：</p><ul><li>必须经过 Code Review。</li><li>提交 PR 时，建议标注“本功能由 Claude 辅助生成，人工校验通过”。</li><li><strong>责任归属</strong>：谁提交了 AI 生成的代码，谁就对这行代码负责。出了 Bug 不能怪 AI。</li></ul><h3 id="_15-2-3-prompt-资产化" tabindex="-1">15.2.3 Prompt 资产化 <a class="header-anchor" href="#_15-2-3-prompt-资产化" aria-label="Permalink to &quot;15.2.3 Prompt 资产化&quot;">​</a></h3><p>好的 Prompt 是团队的资产。</p><ul><li>建立内部的 Prompt 库（或者共享的 <code>.clauderc</code> 配置）。</li><li>将常用的复杂指令固化为 <code>Skill</code>。</li></ul><h2 id="_15-3-培训与推广" tabindex="-1">15.3 培训与推广 <a class="header-anchor" href="#_15-3-培训与推广" aria-label="Permalink to &quot;15.3 培训与推广&quot;">​</a></h2><h3 id="_15-3-1-结对编程-pair-programming" tabindex="-1">15.3.1 结对编程 (Pair Programming) <a class="header-anchor" href="#_15-3-1-结对编程-pair-programming" aria-label="Permalink to &quot;15.3.1 结对编程 (Pair Programming)&quot;">​</a></h3><p>组织“AI 结对编程”工作坊。</p><ul><li>找一个实际的 Ticket。</li><li>大家围在一起，看熟练的同事如何指挥 Claude 解决问题。</li><li>这种直观的演示比任何 PPT 都有效。</li></ul><h3 id="_15-3-2-黑客松-hackathon" tabindex="-1">15.3.2 黑客松 (Hackathon) <a class="header-anchor" href="#_15-3-2-黑客松-hackathon" aria-label="Permalink to &quot;15.3.2 黑客松 (Hackathon)&quot;">​</a></h3><p>举办一次“AI 辅助开发黑客松”。</p><ul><li>主题：用一天时间，利用 Claude Code + MCP 开发一个内部工具。</li><li>目的：让大家在实战中体验 MCP 的强大连接能力。</li></ul><h2 id="_15-4-度量与持续改进" tabindex="-1">15.4 度量与持续改进 <a class="header-anchor" href="#_15-4-度量与持续改进" aria-label="Permalink to &quot;15.4 度量与持续改进&quot;">​</a></h2><p>如何证明引入 Claude Code 是值得的？</p><h3 id="_15-4-1-关注正确的指标" tabindex="-1">15.4.1 关注正确的指标 <a class="header-anchor" href="#_15-4-1-关注正确的指标" aria-label="Permalink to &quot;15.4.1 关注正确的指标&quot;">​</a></h3><ul><li><strong>不要看</strong>：生成的代码行数（LOC）。AI 可以轻松生成一万行垃圾代码。</li><li><strong>要看</strong>： <ul><li><strong>Cycle Time</strong>：从需求提出到上线的周期是否缩短了？</li><li><strong>Bug Rate</strong>：引入 AI 后，Bug 是变多了还是变少了？（通常测试覆盖率高了，Bug 会变少）。</li><li><strong>Developer Happiness</strong>：大家是否觉得工作更开心了？</li></ul></li></ul><h2 id="结语-拥抱-ai-原生开发时代" tabindex="-1">结语：拥抱 AI 原生开发时代 <a class="header-anchor" href="#结语-拥抱-ai-原生开发时代" aria-label="Permalink to &quot;结语：拥抱 AI 原生开发时代&quot;">​</a></h2><p>本书从 Claude Code 的基础操作讲起，深入到 Skill 的定制、MCP 的万物互联，最后落地到真实的工程实战。</p><p>我们正处在软件工程的一个转折点。未来的工程师，不仅要会写代码，更要会<strong>指挥 AI 写代码</strong>，会<strong>设计 AI 与工具的连接</strong>。</p><p>希望这本书能成为你在这个新时代的航海图。现在，打开你的终端，输入 <code>claude</code>，开始创造属于你的未来吧！</p>',38)])])}const m=e(t,[["render",n]]);export{g as __pageData,m as default};
